INSERT INTO `sys_notice` VALUES (1, 'v3.0.0', '正式发布', '2023-10-24 20:05:32');
INSERT INTO `sys_notice` VALUES (2, 'v3.0.1', '修复一些已知bug', '2023-10-24 20:11:32');
INSERT INTO `sys_notice` VALUES (3, 'v3.0.3', '修复一些已知bug,和新增一些功能：（1）加入手机号和邮箱的正则校验（2）加入滑块组件、评分组件、计数器组件等！\n', '2023-12-19 09:33:25');
INSERT INTO `sys_notice` VALUES (4, 'v3.0.5', '修复一些为止bug，xinz自定义菜单相关配色', '2023-12-26 14:34:44');
INSERT INTO `sys_notice` VALUES (5, 'v3.0.6', '新增数据可视化图表', '2023-12-28 14:22:38');
INSERT INTO `sys_notice` VALUES (6, 'v3.0.7', '修改login页面样式，修改代码生成bug，修改默认密码bug，修改日志bug，修改一些格式问题', '2024-09-02 20:03:17');
INSERT INTO `sys_notice` VALUES (7, 'v3.0.8', '（1）修改前端样式；\n（2）实现多图片上传组件\n（3）通过构建记录进行回显构建\n（4）优化后端Bug', '2024-09-26 15:32:47');
INSERT INTO `sys_notice` VALUES (8, 'v3.0.9', '修改一些一致bug，但是不建议使用', '2024-10-17 19:06:43');
INSERT INTO `sys_notice` VALUES (9, 'v3.1.0', '修复一些已知bug，生成时可加入关联表属性，自定义是否加入查询，优化一些技术样式，修改背景色等等\n', '2024-10-17 19:07:29');
INSERT INTO `sys_notice` VALUES (10, 'v2026.0.1', '角色管理中默认关联问题;\n删除无用 permisiion 数据; \n修改默认配色 ;\n前端公钥加密，后端私钥解密;\n处理 layui 遗留警告;\n处理动画警告 ;\nlayout 移动适配 ;\n普通用户默认权限处理;\nID 更换为序列号 ;\n编辑弹框更换样式;\n用户管理表单组件样式、内容细化（表单弹框换成抽屉组件、对账户名、手机号、邮箱号进行唯一确定）;\n角色管理表单组件样式、内容细化 ;\n菜单管理新增更多规则校验 ;\nMenu 和 Logo 组件修改动画逻辑 ;\n下滑滚动栏的更换 ，替换原来又粗又黑的难看的下滑滚轮 ;\n登录页面样式更换 ;\n注册页面样式更换 ;\n找回密码页面样式更换 ;\n通用样式类提取;\n后台首页样式布局内容修改 ;\n自定义主题色 ;\n在线用户 ;\n切换页面执行动画效果;\n在线用户+WebSocket 实时更新 ;\n新增查询组件 ;\n新增设置系统外观参数组件 ;\n解决打包相关问题 （配置 nginx）;\n多环境配置文件;\n新增网络超时提示 ;\n新增数据字典 ;\n代码生成器优化 1：修改权限位置;\n代码生成器优化 2：新增查询权限;\n代码生成器优化 3：修改布局样式;\n代码生成器优化 4：添加字典关联 ;\n代码生成器优化 5：新增 sql 语句进行构建代码;\n代码生成器优化 6:  create_time和update_time数据回显驼峰化的问题 ;\n代码生成器优化 7：el-dialog 更换为 el-drawer;\n代码生成器优化 8：校验表名是否以“sys_”开头 ;\n代码生成器优化 9：校验构建的表名是否在系统表中（通过字典列表来进行判断）;\n', '2025-06-24 10:44:50');
